variable "region" {
  description = "AWS region"
  type        = string
  default     = "eu-west-1"
}

variable "pci" {}
variable "pillar" {}
variable "repo" {}
variable "aws_account_id" {}

variable "product" {
  description = "Product name"
  type        = string
}

variable "service" {
  description = "Service name"
  type        = string
}

variable "team" {
  description = "Team name"
  type        = string
}

variable "env" {
  description = "Environment name (dev, staging, prod)"
  type        = string
}

# ── Admin API (from 200-service outputs) ─────────────────────────────────────

variable "admin_api_id" {
  description = "API Gateway REST API ID for the admin API"
  type        = string
}

variable "admin_api_invoke_url" {
  description = "Admin API invoke URL (e.g. https://<id>.execute-api.eu-west-1.amazonaws.com/<stage>)"
  type        = string
}

# ── Okta OIDC (inbound JWT validation on the gateway) ────────────────────────

variable "okta_issuer_url" {
  description = "Okta OIDC issuer URL (e.g. https://yourco.okta.com/oauth2/default)"
  type        = string
}

variable "okta_client_id" {
  description = "Okta OIDC client ID (same SPA app used by the dashboard)"
  type        = string
}

variable "okta_audience" {
  description = "Expected audience claim in Okta access tokens"
  type        = string
  default     = "api://default"
}

# ══════════════════════════════════════════════════════════════════════════════
# AgentCore Gateway — read-only MCP surface over the Admin API
# ══════════════════════════════════════════════════════════════════════════════
#
# Inbound auth:  Okta JWT (validated by Gateway authorizer)
# Outbound auth: IAM SigV4 (Gateway service role → API Gateway)
#
# NOTE: These resources use the aws_bedrockagentcore_* provider resources.
# Attribute names are based on the provider resource list and AgentCore docs.
# Verify against Terraform AWS provider docs — some may need adjustment.
# ══════════════════════════════════════════════════════════════════════════════

# ── IAM role for AgentCore Gateway (outbound calls to admin API) ─────────────
resource "aws_iam_role" "gateway" {
  name = "${local.prefix}-agentcore-gateway"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "bedrock-agentcore.amazonaws.com"
        }
        Action = "sts:AssumeRole"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

resource "aws_iam_role_policy" "gateway_invoke_api" {
  name = "invoke-admin-api"
  role = aws_iam_role.gateway.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "execute-api:Invoke"
        Resource = "arn:aws:execute-api:${var.region}:${data.aws_caller_identity.current.account_id}:${var.admin_api_id}/${var.env}/GET/api/*"
      }
    ]
  })
}

# ── Workload identity (inbound JWT validation) ──────────────────────────────
resource "aws_bedrockagentcore_workload_identity" "mcp" {
  name = "${local.prefix}-mcp-identity"

  identity_provider_config {
    okta_config {
      issuer_url = var.okta_issuer_url
      audience   = [var.okta_audience]
    }
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── Gateway ─────────────────────────────────────────────────────────────────
resource "aws_bedrockagentcore_gateway" "mcp" {
  name        = "${local.prefix}-mcp-gateway"
  description = "Read-only MCP gateway for Agent HAL admin API"

  protocol_type = "MCP"
  role_arn      = aws_iam_role.gateway.arn

  authorizer_type = "CUSTOM_JWT"
  authorizer_configuration {
    custom_jwt_authorizer_configuration {
      discovery_url    = "${var.okta_issuer_url}/.well-known/openid-configuration"
      allowed_audience = [var.okta_audience]
      allowed_clients  = [var.okta_client_id]
    }
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── Gateway target (Admin API + OpenAPI spec, IAM outbound auth) ─────────────
resource "aws_bedrockagentcore_gateway_target" "admin_api" {
  name       = "${local.prefix}-admin-api"
  gateway_id = aws_bedrockagentcore_gateway.mcp.id

  description = "Agent HAL read-only admin API (IAM auth)"

  target_configuration {
    rest_api_target {
      url = var.admin_api_invoke_url

      # OpenAPI spec defining the MCP tool surface
      open_api_schema = file("${path.module}/../../mcp/openapi-readonly.json")
    }
  }

  # IAM-based outbound authorization (SigV4)
  outbound_authorization {
    authorization_type = "IAM"
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── AgentCore Gateway ────────────────────────────────────────────────────────
output "gateway_id" {
  description = "AgentCore Gateway ID"
  value       = aws_bedrockagentcore_gateway.mcp.id
}

output "gateway_endpoint" {
  description = "AgentCore Gateway MCP endpoint URL"
  value       = aws_bedrockagentcore_gateway.mcp.endpoint_url
}

output "gateway_role_arn" {
  description = "IAM role ARN used by the gateway for outbound API calls"
  value       = aws_iam_role.gateway.arn
}

output "workload_identity_id" {
  description = "Workload identity ID for inbound JWT validation"
  value       = aws_bedrockagentcore_workload_identity.mcp.id
}

