resource "aws_api_gateway_rest_api_policy" "admin" {
  rest_api_id = aws_api_gateway_rest_api.admin.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowVPCEndpoint"
        Effect    = "Allow"
        Principal = "*"
        Action    = "execute-api:Invoke"
        Resource  = "${aws_api_gateway_rest_api.admin.execution_arn}/*"
        Condition = {
          StringEquals = {
            "aws:SourceVpce" = data.aws_vpc_endpoint.execute_api.id
          }
        }
      },
      {
        Sid    = "AllowAgentCoreGateway"
        Effect = "Allow"
        Principal = {
          Service = "bedrock-agentcore.amazonaws.com"
        }
        Action   = "execute-api:Invoke"
        Resource = "${aws_api_gateway_rest_api.admin.execution_arn}/${var.env}/GET/api/*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = local.account_id
          }
        }
      }
    ]
  })
}

